'use strict';

// ----------------------------
// Storage (tema persistido)
// ----------------------------
const KEY = 'miniapp:ui';
const VERSION = 1;

function defaultUi() { return { theme: 'light' }; }

function loadUi() {
  const raw = localStorage.getItem(KEY);
  if (raw === null) return defaultUi();
  try {
    const env = JSON.parse(raw);
    if (env?.version !== VERSION) return defaultUi();
    const theme = env?.data?.theme === 'dark' ? 'dark' : 'light';
    return { theme };
  } catch {
    return defaultUi();
  }
}

function saveUi(ui) {
  const env = { version: VERSION, data: { theme: ui.theme === 'dark' ? 'dark' : 'light' } };
  localStorage.setItem(KEY, JSON.stringify(env));
}

// ----------------------------
// Router (hash + params)
// ----------------------------
function getPath() {
  const h = window.location.hash || '#/';
  return (h.startsWith('#') ? h.slice(1) : h) || '/';
}

function splitPath(path) {
  return path.split('?')[0].split('#')[0].split('/').filter(Boolean);
}

function matchRoute(path) {
  const seg = splitPath(path);
  if (seg.length === 0) return { name: 'home', params: {} };
  if (seg[0] === 'itens' && seg.length === 1) return { name: 'itens', params: {} };
  if (seg[0] === 'itens' && seg.length === 2) {
    const id = Number(seg[1]);
    if (!Number.isFinite(id)) return { name: 'notfound', params: {} };
    return { name: 'item', params: { id } };
  }
  if (seg[0] === 'settings' && seg.length === 1) return { name: 'settings', params: {} };
  return { name: 'notfound', params: {} };
}

function go(path) { window.location.hash = '#' + path; }

// ----------------------------
// State
// ----------------------------
const itens = [
  { id: 1, nome: 'Café' },
  { id: 2, nome: 'Leite' },
  { id: 3, nome: 'Pão' },
];

let state = {
  ui: loadUi(),
  route: matchRoute(getPath()),
};

function setState(patch) { state = { ...state, ...patch }; render(); }

window.addEventListener('hashchange', () => {
  setState({ route: matchRoute(getPath()) });
});

// ----------------------------
// Render (string controlada)
// ----------------------------
function render() {
  const root = document.querySelector('#app');
  const { name, params } = state.route;

  document.body.dataset.theme = state.ui.theme;

  if (name === 'home') {
    root.innerHTML = `<h2>Home</h2><p>Use o menu acima.</p>`;
    return;
  }

  if (name === 'itens') {
    const lis = itens.map((it) => `<li><a href="#/itens/${it.id}">${it.nome}</a></li>`).join('');
    root.innerHTML = `<h2>Lista</h2><ul>${lis}</ul>`;
    return;
  }

  if (name === 'item') {
    const it = itens.find((x) => x.id === params.id);
    if (!it) { root.innerHTML = `<h2>404</h2><p>Item não encontrado.</p>`; return; }
    root.innerHTML = `<h2>Detalhe</h2><p>#${it.id} — ${it.nome}</p><p><a href="#/itens">Voltar</a></p>`;
    return;
  }

  if (name === 'settings') {
    root.innerHTML = `
      <h2>Settings</h2>
      <p>Tema atual: <b>${state.ui.theme}</b></p>
      <button id="toggle" type="button">Alternar tema</button>
    `;

    const btn = document.querySelector('#toggle');
    btn.addEventListener('click', () => {
      const next = state.ui.theme === 'dark' ? 'light' : 'dark';
      const ui = { ...state.ui, theme: next };
      state = { ...state, ui };
      saveUi(ui);
      render();
    });
    return;
  }

  root.innerHTML = `<h2>404</h2><p>Rota não encontrada.</p>`;
}

render();
if (!window.location.hash) go('/');
console.log('[miniapp] pronto');
